-- =====================================================
-- 2. Структурированные критерии перехода shoulder_biceps_tenotomy
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев. Фазы 1–4 (терминальная фаза 4 несёт критерии).
--    measurement (vas_score/pain) НЕ используется: в источнике порогов по боли в критериях
--    перехода нет — почти все критерии качественные (instructor_check / self_report).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (ранняя защита → восстановление активных движений)
  (1, 'full_passive_rom_p1',    'Полный пассивный объём движений плеча и локтя (по оценке куратора очно)',                     'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'pain_decreasing_p1',     'Боль день ото дня убывает, а не нарастает',                                                  'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль с каждым днём становится меньше, а не больше?', 'Сравните боль сегодня с тем, что было пару дней назад', 20::smallint, TRUE),
  (1, 'sleep_without_pain_p1',  'Удаётся спать без частых пробуждений от боли в плече',                                       'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается спать без частых пробуждений от боли в плече?', 'Оцените сон за последние несколько ночей', 30::smallint, TRUE),
  (1, 'wound_healing_p1',       'Разрез заживает без признаков инфекции (оценка куратора)',                                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'phase1_exercises_ok_p1', 'Упражнения этапа выполняются без боли и затруднений',                                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление активных движений → укрепление)
  (2, 'full_active_rom_p2',     'Полный активный объём движений плеча и локтя (по оценке куратора очно)',                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'weeks_since_op_4_p2',    'Прошло не менее 4 недель от операции — окончание защиты бицепса от нагрузки на сгибание локтя', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'scapular_control_p2',    'Правильная статика и динамический контроль лопатки при движениях (оценка куратора)',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'no_biceps_cramp_p2',     'Нет судорожной боли в брюшке бицепса при активном сгибании без сопротивления (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (2, 'waist_level_adl_p2',     'Удаётся свободно поднимать руку и выполнять дела на уровне пояса без боли',                   'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается свободно поднять руку и выполнять дела на уровне пояса без боли?', 'Например, одеться, поесть, взять предмет с полки на уровне пояса', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (укрепление → продвинутое укрепление и возврат к активности)
  (3, 'near_full_painfree_p3',  'Почти полный безболезненный активный объём движений во всех направлениях (оценка куратора очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'cuff_strength_4_p3',     'Достаточная сила мышц манжеты и лопатки для активности на уровне груди (ориентир — не менее 4 из 5 по оценке куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'painfree_exercises_p3',  'Упражнения этапа выполняются без боли и без болезненности на следующий день',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, FALSE),
  (3, 'tolerate_strength_p3',   'Начальные силовые упражнения переносятся без усиления симптомов',                            'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Переносите ли начальные силовые упражнения без усиления симптомов?', 'Оцените по нескольким занятиям с лёгким весом', 40::smallint, TRUE),

  -- Фаза 4 (терминальная) — критерии возврата к спорту / тяжёлой работе
  (4, 'strength_90pct_p4',      'Сила оперированной руки не менее 90% относительно здоровой стороны (ориентир из родственных протоколов, оценивает куратор очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'full_painfree_rom_p4',   'Полный безболезненный объём движений поддерживается',                                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'no_compensation_p4',     'Нет компенсаторных движений при силовых и функциональных тестах (оценка куратора)',          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, FALSE),
  (4, 'no_pain_progressive_p4', 'Нет боли при прогрессивных силовых нагрузках',                                               'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Нет ли боли при постепенно нарастающих силовых нагрузках?', 'Оцените по реакции плеча после силовых занятий', 40::smallint, TRUE),
  (4, 'md_clearance_p4',        'Получен письменный допуск лечащего врача к спорту/тяжёлой работе',                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_biceps_tenotomy' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
